sql:
SELECT ref_id, COUNT(variant_id) AS variant_count
FROM variant_calls
GROUP BY ref_id;

SELECT species
FROM reference_sequences
WHERE assembly = 'GRCh38';

SELECT variant_type, COUNT(*) AS variant_count
FROM variant_calls
GROUP BY variant_type;

external_knowledge:
- 'senior navigators' refers to users with the 'administrator' role;
- 'expedition' is a metaphor for the data exploration process involving variant calls and gene data;
- 'treasures' represent variant calls, and the 'types' and 'ancient names' refer to the variant type and gene name respectively;
- 'peeked at' means the action of 'view' access type.

sql:
SELECT COUNT(DISTINCT variant_id) AS total_unique_variants_accessed
FROM access_logs
WHERE access_date >= DATE('now', '-30 days');

external_knowledge:
- 'High-impact variants' are genetic changes that have a significant effect on the gene's function.;
- 'Effects' refer to the functional impact of the variant, such as altering the amino acid sequence.;
- The term 'threonine dehydratase' is the gene name, which helps in identifying the specific gene of interest.

sql:
SELECT COUNT(*) AS total_sequences
FROM reference_sequences
WHERE species = 'Homo sapiens';

SELECT variant_id, MAX(created_at) AS latest_creation_date
FROM variant_calls
GROUP BY variant_id;

SELECT MAX(count) AS max_variant_count
FROM (
    SELECT variant_type, COUNT(*) AS count
    FROM variant_calls
    GROUP BY variant_type
);

SELECT COUNT(gene_id) AS affected_genes
FROM variant_gene
WHERE variant_id = 1;

SELECT species, assembly, COUNT(*) AS total_sequences
FROM reference_sequences
GROUP BY species, assembly;
